$(document).ready((function(){$(".main_input_file").change((function(e){e.preventDefault();for(var t=[],n=0;n<$(this).get(0).files.length;++n)t.push(" "+$(this).get(0).files[n].name);$(".f_name").val(t.join(", "))})),document.querySelector(".header__burger").addEventListener("click",()=>{document.querySelector(".sidebar").classList.toggle("disable")})}));